import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  CartesianGrid,
} from "recharts";

export default function MMFRateChart({ data }) {
  return (
    <div style={{ width: "100%", height: 300 }}>
      <ResponsiveContainer>
        <LineChart data={data}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="month" />
          <YAxis
            tickFormatter={(v) => `${v}%`}
            domain={["dataMin - 0.5", "dataMax + 0.5"]}
          />
          <Tooltip
            formatter={(value) => [`${value}%`, "Rate"]}
          />
          <Line
            type="monotone"
            dataKey="rate"
            stroke="#1ba9da"
            strokeWidth={3}
            dot={{ r: 4 }}
          />
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
}
